#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

long long dp[1005][605];

long long solve(int n, int w) {
    for (int i = 0; i <= n; i++) {
        for (int j = 0; j <= 600; j++) {
            dp[i][j] = 0;
        }
    }
    dp[1][0] = 9;
    for (int i = 2; i <= n; i++) {
        for (int j = -300; j <= 300; j++) {
            for (int k = -9; k <= 9; k++) {
                if (j + k >= -300 && j + k <= 300) {
                    dp[i][j + k + 300] = (dp[i][j + k + 300] + dp[i - 1][j + 300]) % MOD;
                }
            }
        }
    }
    return dp[n][w + 300];
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n, w;
        scanf("%d %d", &n, &w);
        printf("%lld\n", solve(n, w));
    }
    return 0;
}

